function abrirSessao(id) {
  currentSessionId = id;
  limparChat();

  // Atualiza destaque na sidebar
  document.querySelectorAll('.pe-session-item').forEach(function (el) {
    el.classList.toggle('active', parseInt(el.dataset.id) === id);
