  border: 1px solid rgba(0,212,255,0.3);
  color: #00d4ff;
  padding: 10px 24px;
  border-radius: 10px;
  cursor: pointer;
  font-size: 14px;
  transition: background 0.2s;
}
.pe-empty-start-btn:hover { background: rgba(0,212,255,0.2); }

/* Input area */
.pe-input-area {
  display: flex;
  gap: 10px;
  align-items: flex-end;
  padding: 12px 20px;
  border-top: 1px solid rgba(255,255,255,0.07);
  background: rgba(0,0,0,0.2);
  max-width: 820px;
  width: 100%;
  margin: 0 auto;
  align-self: stretch;
}
.pe-textarea {
  flex: 1;
  background: rgba(255,255,255,0.05);
  border: 1px solid rgba(255,255,255,0.1);
  border-radius: 12px;
  color: #e0f7fa;
  font-family: inherit;
  font-size: 14px;
  line-height: 1.5;
  padding: 11px 14px;
  resize: none;
  outline: none;
  min-height: 46px;
  max-height: 150px;
  transition: border-color 0.2s;
}
.pe-textarea:focus { border-color: rgba(0,212,255,0.4); }
.pe-textarea::placeholder { color: rgba(176,190,197,0.35); }
.pe-send-btn {
  width: 46px; height: 46px;
  background: linear-gradient(135deg, rgba(0,212,255,0.3), rgba(0,212,255,0.1));
  border: 1px solid rgba(0,212,255,0.4);
  border-radius: 12px;
  color: #00d4ff;
  cursor: pointer;
  font-size: 18px;
  display: flex; align-items: center; justify-content: center;
  transition: background 0.2s, transform 0.1s;
  flex-shrink: 0;
}
.pe-send-btn:hover { background: rgba(0,212,255,0.25); }
.pe-send-btn:active { transform: scale(0.95); }
.pe-send-btn:disabled { opacity: 0.35; cursor: not-allowed; }
.pe-hint {
  font-size: 11px;
  color: rgba(176,190,197,0.3);
  text-align: center;
  padding: 4px 0 10px;
}

/* Mobile */
@media (max-width: 768px) {
  .pe-sidebar {
    position: fixed;
    top: 0; left: 0; bottom: 0;
    z-index: 300;
    transform: translateX(-100%);
  }
  .pe-sidebar.open { transform: translateX(0); }
  .pe-sidebar-toggle { display: flex; align-items: center; justify-content: center; }
  .pe-chat-area { padding-top: 60px; }
}
